"""Панель выбора фильтров с поддержкой множественного выбора и сохранённых параметров.UX (MVP-честный):  1. Слева — список фильтров с чекбоксами (QListWidget).  2. Справа — форма параметров текущего «активного» фильтра (выделенной строки).  3. Пользователь правит параметры → жмёт «Сохранить параметры».     Параметры сохраняются именно для этого фильтра во внутреннем словаре.  4. В запуск идут ВСЕ отмеченные чекбоксами фильтры со своими сохранёнными     параметрами. Параметры неотмеченных тоже хранятся (вдруг пользователь     вернётся к ним в этой же сессии).Если отмечен только один фильтр — поведение совпадает со старым(одиночный выбор). Первый встроенный фильтр отмечен по умолчанию."""from __future__ import annotationsfrom typing import Anyfrom PySide6.QtCore import Qtfrom PySide6.QtWidgets import (    QGroupBox, QHBoxLayout, QLabel, QListWidget, QListWidgetItem,    QMessageBox, QPushButton, QVBoxLayout, QWidget,)from ...core.registry import Registryfrom .params_editor import ParamsEditorclass FilterPanel(QGroupBox):    def __init__(self, registry: Registry, parent: QWidget | None = None) -> None:        super().__init__("Фильтры (можно выбрать несколько)", parent)        self._registry = registry        # Сохранённые параметры для каждого фильтра (по имени).        self._saved_params: dict[str, dict[str, Any]] = {}        # Имя фильтра, параметры которого сейчас видны в форме справа.        self._current_name: str | None = None        self._list = QListWidget()        self._list.setSelectionMode(QListWidget.SingleSelection)        for i, name in enumerate(registry.list_filters()):            item = QListWidgetItem(name)            item.setFlags(item.flags() | Qt.ItemIsUserCheckable)            # Первый фильтр — включён по умолчанию, остальные — выключены.            item.setCheckState(Qt.Checked if i == 0 else Qt.Unchecked)            self._list.addItem(item)            # Инициализируем сохранённые параметры — по дефолтам схемы.            impl = registry.get_filter(name)            self._saved_params[name] = _defaults_from_schema(impl.params_schema)        self._list.currentItemChanged.connect(self._on_current_changed)        self._editor = ParamsEditor()        self._save_button = QPushButton("Сохранить параметры")        self._save_button.clicked.connect(self._on_save_clicked)        self._hint = QLabel(            "Отметьте галочками нужные фильтры. "            "Параметры правятся для выделенной строки и вступают в силу "            "после нажатия «Сохранить параметры»."        )        self._hint.setWordWrap(True)        # Компоновка.        left = QVBoxLayout()        left.addWidget(self._list, 1)        right = QVBoxLayout()        right.addWidget(self._hint)        right.addWidget(self._editor, 1)        right.addWidget(self._save_button)        outer = QHBoxLayout(self)        outer.addLayout(left, 1)        outer.addLayout(right, 2)        # Инициализация — выбрать первую строку.        if self._list.count() > 0:            self._list.setCurrentRow(0)    # ---------- публичный API ------------------------------------------------    def selected_filter_specs(self) -> list[tuple[str, dict[str, Any]]]:        """Возвращает список (filter_name, params) только для отмеченных."""        # Перед сбором зафиксируем изменения активной формы, чтобы не        # потерять несохранённую правку пользователя (UX-страховка).        self._autosave_current()        out: list[tuple[str, dict[str, Any]]] = []        for i in range(self._list.count()):            item = self._list.item(i)            if item.checkState() == Qt.Checked:                name = item.text()                out.append((name, dict(self._saved_params[name])))        return out    # ---------- internals ---------------------------------------------------    def _on_current_changed(self, current: QListWidgetItem | None,                            _previous: QListWidgetItem | None) -> None:        # Сохранить изменения предыдущей формы автоматически.        self._autosave_current()        if current is None:            self._current_name = None            self._editor.set_schema({})            return        name = current.text()        impl = self._registry.get_filter(name)        self._editor.set_schema(impl.params_schema)        # Восстановить сохранённые значения, подставив их в поля формы.        saved = self._saved_params.get(name, {})        if saved:            self._apply_values_to_editor(saved)        self._current_name = name    def _on_save_clicked(self) -> None:        if self._current_name is None:            return        try:            self._saved_params[self._current_name] = dict(self._editor.values())        except Exception as e:            QMessageBox.critical(self, "SAFR",                                 f"Ошибка чтения параметров: {e}")            return        QMessageBox.information(            self, "SAFR",            f"Параметры фильтра «{self._current_name}» сохранены."        )    def _autosave_current(self) -> None:        """Тихо сохранить текущие значения в словарь (без диалога)."""        if self._current_name is None:            return        try:            self._saved_params[self._current_name] = dict(self._editor.values())        except Exception:            # если значения некорректны — не перетираем сохранённые ранее            pass    def _apply_values_to_editor(self, values: dict[str, Any]) -> None:        """Мягко выставить значения в уже построенной форме ParamsEditor."""        # Доступ к внутренним виджетам через словарь редактора.        widgets = getattr(self._editor, "_widgets", {})        schema = getattr(self._editor, "_schema", {})        for key, v in values.items():            if key not in widgets or key not in schema:                continue            w = widgets[key]            t = schema[key]["type"]            try:                if t == "int":                    w.setValue(int(v))                elif t == "float":                    w.setValue(float(v))                elif t == "bool":                    w.setChecked(bool(v))                elif t == "enum":                    idx = w.findText(str(v))                    if idx >= 0:                        w.setCurrentIndex(idx)            except Exception:                passdef _defaults_from_schema(schema: dict[str, dict[str, Any]]) -> dict[str, Any]:    return {k: spec["default"] for k, spec in schema.items()}